/* Physical staging tables for ADS operating-view procedures. */
CREATE TABLE IF NOT EXISTS TMP_ADS_ORG_SCOPE (
    LEAF_ORG_ID VARCHAR(7),
    ANCESTOR_ORG_ID VARCHAR(7),
    ORG_LEVEL VARCHAR(10)
);
CREATE TABLE IF NOT EXISTS TMP_ADS_DEADLINE_EXPIRE (    DATA_DATE VARCHAR(8), CUST_ID VARCHAR(20), PRDKT_ID VARCHAR(40), STATIS_TYP VARCHAR(1),    EXPR_DATE VARCHAR(8), EXPR_AMT NUMBER(20,2), PERIOD_START VARCHAR(8), PERIOD_END VARCHAR(8));
CREATE TABLE IF NOT EXISTS TMP_ADS_DEADLINE_WINDOW (    DATA_DATE VARCHAR(8), CUST_ID VARCHAR(20), STATIS_TYP VARCHAR(1), WINDOW_START VARCHAR(8),    WINDOW_END VARCHAR(8), NEXT_EXPR_DATE VARCHAR(8));
CREATE TABLE IF NOT EXISTS TMP_ADS_POTN_BASE (    DATA_DATE VARCHAR(8), CUST_ID VARCHAR(20), LVL_CRIT VARCHAR(2), AUM_MTH_AVG NUMBER(20,2),    AUM_BAL NUMBER(20,2), POST_ID VARCHAR(20), ORG_ID VARCHAR(7));
CREATE TABLE IF NOT EXISTS TMP_ADS_LOST_BASE (    DATA_DATE VARCHAR(8), CUST_ID VARCHAR(20), LVL_CHURN VARCHAR(2), PREV_AUM NUMBER(20,2),    CURR_AUM NUMBER(20,2), POST_ID VARCHAR(20), ORG_ID VARCHAR(7));
CREATE TABLE IF NOT EXISTS TMP_ADS_NEW_CUST_BASE (    DATA_DATE VARCHAR(8), CUST_ID VARCHAR(20), OPEN_DATE VARCHAR(8), NEW_CUST_CYCLE VARCHAR(1),    KYC_RATE NUMBER(10,4), POST_ID VARCHAR(20), ORG_ID VARCHAR(7));
CREATE TABLE IF NOT EXISTS TMP_ADS_SLEEP_BASE (    DATA_DATE VARCHAR(8), CUST_ID VARCHAR(20), AUM_BAL NUMBER(20,2), ACTIVE_TX_FLG VARCHAR(1),    WAKE_STATE VARCHAR(1), POST_ID VARCHAR(20), ORG_ID VARCHAR(7));
